const body = $input.first().json.body || {};
const program_name = (body.program_name || '').toUpperCase().trim();
if (!program_name) throw new Error('program_name es requerido');
return { json: { program_name } };

const prog      = $('Busca Datos Programa').first().json;
const relations = $('Busca Relaciones').all().map(i => i.json);

if (!prog.program_id) {
  throw new Error(`Programa '${$('Extrae Params').first().json.program_name}' no encontrado`);
}

const use_cache = (
  prog.doc_status === 'completed' &&
  prog.cached_checksum === prog.current_checksum &&
  prog.existing_doc_id != null
);

const callers   = [...new Map(relations.filter(r => r.tipo === 'caller').map(r => [r.nombre, r])).values()];
const calls     = [...new Map(relations.filter(r => r.tipo === 'call').map(r => [r.nombre, r])).values()];
const copybooks = [...new Map(relations.filter(r => r.tipo === 'copybook').map(r => [r.nombre, r])).values()];
const files     = [...new Map(relations.filter(r => r.tipo === 'file').map(r => [r.nombre, r])).values()];
const db2       = [...new Map(relations.filter(r => r.tipo === 'db2').map(r => [r.nombre, r])).values()];
const sharedRaw = relations.filter(r => r.tipo === 'shared_copy');

const sharedByBook = {};
sharedRaw.forEach(r => {
  if (!sharedByBook[r.nombre]) sharedByBook[r.nombre] = [];
  if (!sharedByBook[r.nombre].includes(r.detalle)) sharedByBook[r.nombre].push(r.detalle);
});

const context = [
  callers.length > 0
    ? `PROGRAMAS QUE INVOCAN A ESTE PROGRAMA (callers):\n${callers.map(c => `- ${c.nombre} (tipo: ${c.detalle})`).join('\n')}`
    : 'PROGRAMAS QUE INVOCAN A ESTE PROGRAMA: ninguno registrado en el sistema',
  calls.length > 0
    ? `PROGRAMAS QUE ESTE PROGRAMA INVOCA (callees):\n${calls.map(c => `- ${c.nombre} (tipo: ${c.detalle}, línea ${c.extra})`).join('\n')}`
    : 'PROGRAMAS QUE INVOCA: ninguno',
  copybooks.length > 0
    ? `COPYBOOKS INCLUIDOS:\n${copybooks.map(c => `- ${c.nombre} en división ${c.detalle} (línea ${c.extra})`).join('\n')}`
    : 'COPYBOOKS: ninguno',
  files.length > 0
    ? `ARCHIVOS QUE ACCEDE:\n${files.map(f => `- ${f.nombre} → ${f.detalle} (${f.extra || 'tipo desconocido'})`).join('\n')}`
    : 'ARCHIVOS: ninguno',
  db2.length > 0
    ? `TABLAS DB2:\n${db2.map(d => `- ${d.detalle ? d.detalle + '.' : ''}${d.nombre} [operaciones: ${d.extra}]`).join('\n')}`
    : 'TABLAS DB2: ninguna',
  Object.keys(sharedByBook).length > 0
    ? `PROGRAMAS QUE COMPARTEN COPYBOOKS CON ESTE PROGRAMA (impacto indirecto ante cambios en copybooks):\n${Object.entries(sharedByBook).map(([book, progs]) => `- ${book}: ${progs.join(', ')}`).join('\n')}`
    : ''
].filter(Boolean).join('\n\n');

return {
  json: {
    ...prog,
    use_cache,
    relations_context: context
  }
};

const row  = $input.first().json;
const prog = $('Evalúa Caché y Prepara Contexto').first().json;
return {
  json: {
    success:      true,
    from_cache:   true,
    program_name: prog.program_name,
    analysis:     row.analysis_json,
    generated_at: row.generated_at
  }
};

const chainOut = $input.first().json;
const prog     = $('Evalúa Caché y Prepara Contexto').first().json;

let rawText = (chainOut.text || chainOut.output || '').trim();
rawText = rawText.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

let analysis;
try {
  analysis = JSON.parse(rawText);
} catch(e) {
  throw new Error('LLM no retornó JSON válido: ' + rawText.substring(0, 300));
}

analysis.program_name             = prog.program_name;
analysis.calling_programs         = analysis.calling_programs         || [];
analysis.called_programs          = analysis.called_programs          || [];
analysis.copys                    = analysis.copys                    || [];
analysis.file_accesses            = analysis.file_accesses            || [];
analysis.db2_tables               = analysis.db2_tables               || [];
analysis.shared_copybook_programs = analysis.shared_copybook_programs || [];
analysis.calling_count            = Number(analysis.calling_count)    || analysis.calling_programs.length;
analysis.called_count             = Number(analysis.called_count)     || analysis.called_programs.length;
analysis.impact_risk              = ['HIGH','MEDIUM','LOW'].includes((analysis.impact_risk || '').toUpperCase())
                                    ? analysis.impact_risk.toUpperCase() : 'LOW';
analysis.impact_rationale         = analysis.impact_rationale         || '';
analysis.program_description      = analysis.program_description      || '';
analysis.program_functionality    = analysis.program_functionality    || '';

return {
  json: {
    program_id:                   prog.program_id,
    program_name:                 prog.program_name,
    version_id:                   prog.version_id,
    current_checksum:             prog.current_checksum,
    analysis,
    calling_programs_str:         JSON.stringify(analysis.calling_programs),
    called_programs_str:          JSON.stringify(analysis.called_programs),
    copys_str:                    JSON.stringify(analysis.copys),
    file_accesses_str:            JSON.stringify(analysis.file_accesses),
    db2_tables_str:               JSON.stringify(analysis.db2_tables),
    shared_copybook_programs_str: JSON.stringify(analysis.shared_copybook_programs),
    analysis_json_str:            JSON.stringify(analysis)
  }
};

const data = $('Parsea y Valida JSON').first().json;
return {
  json: {
    success:      true,
    from_cache:   false,
    program_name: data.program_name,
    analysis:     data.analysis,
    generated_at: new Date().toISOString()
  }
};
